// Filtrar pagos con más de 30 días de atraso
const today = new Date();
const thirtyDaysAgo = new Date(today);
thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

const payments = $input.all().map(item => item.json);

// Filtrar por fecha de emisión
const overduePayments = payments.filter(p => {
  if (!p.fecha_emision) return false;
  const emisionDate = new Date(p.fecha_emision);
  return emisionDate < thirtyDaysAgo;
});

if (overduePayments.length === 0) {
  return [{ json: { has_overdue: false, count: 0, payments: [] } }];
}

// Calcular total
const totalAmount = overduePayments.reduce((sum, p) => sum + parseFloat(p.monto || 0), 0);

return [{
  json: {
    has_overdue: true,
    count: overduePayments.length,
    total: totalAmount,
    payments: overduePayments
  }
}];

// Crear mensaje para Telegram
const data = $input.first().json;
const payments = data.payments;

const formatCurrency = (amount) => {
  return new Intl.NumberFormat('es-MX', {
    style: 'currency',
    currency: 'MXN'
  }).format(amount);
};

const formatDate = (dateStr) => {
  const date = new Date(dateStr);
  return date.toLocaleDateString('es-MX');
};

let message = `📊 **Reporte de Pagos Pendientes**\n`;
message += `📅 ${new Date().toLocaleDateString('es-MX')}\n\n`;
message += `⚠️ **${payments.length} factura(s)** con más de 30 días de atraso:\n\n`;

// Top 10 por monto
const sortedPayments = [...payments].sort((a, b) => parseFloat(b.monto) - parseFloat(a.monto));
const topPayments = sortedPayments.slice(0, 10);

topPayments.forEach((p, i) => {
  const daysLate = Math.floor((new Date() - new Date(p.fecha_emision)) / (1000 * 60 * 60 * 24));
  message += `${i + 1}. **${p.cliente}**\n`;
  message += `   💰 ${formatCurrency(p.monto)} - ⏰ ${daysLate} días\n`;
});

if (payments.length > 10) {
  message += `\n... y ${payments.length - 10} más\n`;
}

message += `\n💰 **Total pendiente:** ${formatCurrency(data.total)}`;

return [{
  json: {
    telegram_message: message,
    count: payments.length,
    total: data.total
  }
}];

// Crear alertas en base de datos
const data = $input.first().json;
const payments = data.payments || [];

if (payments.length === 0) {
  return [{ json: { alerts_created: 0 } }];
}

const alerts = payments.map(p => ({
  json: {
    user_id: p.user_id,
    tipo_alerta: 'pago_pendiente_30dias',
    referencia_id: p.id,
    fecha_ejecucion: new Date().toISOString().split('T')[0]
  }
}));

return alerts;
